// backend/utils/helper.ts
import { pbkdf2Sync } from "crypto";
var isValidIp = (ip) => {
  if (!ip) {
    return false;
  }
  const ipv4Regex = /^(?:25[0-5]|2[0-4]\d|1\d\d|[1-9]\d|\d)(?:\.(?:25[0-5]|2[0-4]\d|1\d\d|[1-9]\d|\d)){3}$/;
  const ipv6Regex = /^([a-fA-F0-9:]+)$/;
  return ipv4Regex.test(ip) || ipv6Regex.test(ip);
};
var getClientIp = (c) => {
  const xff = c.req.header("x-forwarded-for");
  if (xff) {
    const ip = xff.split(",")[0]?.trim() || "";
    if (isValidIp(ip)) {
      return ip;
    }
  }
  const realIp = c.req.header("x-real-ip");
  if (realIp && isValidIp(realIp)) {
    return realIp.trim();
  }
  const cfIp = c.req.header("cf-connecting-ip");
  if (cfIp && isValidIp(cfIp)) {
    return cfIp.trim();
  }
  return "0.0.0.0";
};
var enPassword = (username, password) => {
  return pbkdf2Sync(password, username, 1e5, 32, "sha512").toString("hex");
};
var randomString = (length = 16) => {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  let result = "";
  for (let i = 0;i < length; i += 1) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
};
var getAppName = () => {
  return Bun.env.ZNOTE_APP_NAME?.trim() || "ZNote";
};
var getAllowRegister = () => {
  return Bun.env.ZNOTE_ALLOW_REGISTER === "true";
};
var getBearerToken = (c) => {
  const authorization = c.req.header("authorization") || "";
  if (!authorization.startsWith("Bearer ")) {
    return "";
  }
  return authorization.slice(7).trim();
};

