var permanentDeleteNote = async (c) => {
  const uid = Number(c.get("uid"));
  const payload = await c.req.json();
  const { id } = payload || {};
  if (!id || typeof id !== "number") {
    return c.json({
      code: -1000,
      msg: "note.permanent_delete.id_required",
      data: null
    });
  }
  const note = await db.select({ content: notes.content }).from(notes).where(and4(eq5(notes.id, id), eq5(notes.user_id, uid))).get();
  if (!note) {
    return c.json({
      code: -1000,
      msg: "note.permanent_delete.not_found",
      data: null
    });
  }
  const versions = await db.select({ content: noteVersions.content }).from(noteVersions).where(eq5(noteVersions.note_id, id)).all();
  const contents = [note.content, ...versions.map((v) => v.content)].filter(Boolean);
  const fileIdSet = new Set;
  const reg = /zn-[A-Za-z0-9]{8}/g;
  for (const text2 of contents) {
    const matches = text2.matchAll(reg);
    for (const m of matches) {
      fileIdSet.add(m[0]);
    }
  }
  const filePaths = [];
  if (fileIdSet.size > 0) {
    const fileRecords = await db.select({ file_path: files.file_path }).from(files).where(and4(inArray2(files.file_id, [...fileIdSet]), eq5(files.user_id, uid))).all();
    filePaths.push(...fileRecords.map((f) => f.file_path));
  }
  await db.transaction(async (tx) => {
    await tx.delete(noteVersions).where(and4(eq5(noteVersions.note_id, id), eq5(noteVersions.user_id, uid)));
    if (fileIdSet.size > 0) {
      await tx.delete(files).where(and4(inArray2(files.file_id, [...fileIdSet]), eq5(files.user_id, uid)));
    }
    await tx.delete(notes).where(and4(eq5(notes.id, id), eq5(notes.user_id, uid)));
  });
  for (const relativePath of filePaths) {
    try {
      const fullPath = join3(FILES_BASE_PATH, relativePath);
      if (existsSync2(fullPath)) {
        unlinkSync(fullPath);
      }
    } catch {}
  }
  return c.json({
    code: 200,
    msg: "note.permanent_delete.success",
    data: null
  });
};

