// backend/api/import.ts
var import_adm_zip = __toESM(require_adm_zip(), 1);
import { join as join4 } from "path";
import { mkdirSync as mkdirSync2, readdirSync, readFileSync, rmSync, statSync } from "fs";
var importZip = async (c) => {
  const uid = Number(c.get("uid"));
  const formData = await c.req.formData();
  const notebookId = Number(formData.get("notebook_id"));
  const file = formData.get("file");
  if (!notebookId || isNaN(notebookId)) {
    return c.json({ code: -1000, msg: "import.notebook_required", data: null });
  }
  if (!file || !(file instanceof File)) {
    return c.json({ code: -1000, msg: "import.file_required", data: null });
  }
  const owned = await checkNotebookOwnership(notebookId, uid);
  if (!owned) {
    return c.json({ code: -1000, msg: "import.notebook_not_found", data: null });
  }
  const tmpDir = join4("/tmp", `zest_import_${uid}_${Date.now()}`);
  mkdirSync2(tmpDir, { recursive: true });
  try {
    const zipPath = join4(tmpDir, "import.zip");
    await Bun.write(zipPath, file);
    const zip = new import_adm_zip.default(zipPath);
    const extractDir = join4(tmpDir, "extracted");
    zip.extractAllTo(extractDir, true);
    const entries = readdirSync(extractDir);
    const topDirs = entries.filter((e) => {
      try {
        return statSync(join4(extractDir, e)).isDirectory();
      } catch {
        return false;
      }
    });
    const topMds = entries.filter((e) => {
      try {
        return e.endsWith(".md") && statSync(join4(extractDir, e)).isFile();
      } catch {
        return false;
      }
    });
    let rootDir = extractDir;
    if (topDirs.length === 1 && topMds.length === 0) {
      rootDir = join4(extractDir, topDirs[0]);
    }
    const noteEntries = [];
    await db.transaction(async (tx) => {
      async function importDir(dir, parentDbId) {
        const items = readdirSync(dir);
        for (const name of items) {
          const fullPath = join4(dir, name);
          let st;
          try {
            st = statSync(fullPath);
          } catch {
            continue;
          }
          if (st.isDirectory()) {
            const [nb] = await tx.insert(notebooks).values({
              user_id: uid,
              parent_id: parentDbId,
              title: name,
              description: "",
              sort_order: 0,
              created_at: st.mtime,
              updated_at: st.mtime
            }).returning();
            await importDir(fullPath, nb.id);
          }
        }
        for (const name of items) {
          const fullPath = join4(dir, name);
          let st;
          try {
            st = statSync(fullPath);
          } catch {
            continue;
          }
          if (st.isFile() && name.endsWith(".md")) {
            const title = name.replace(/\.md$/, "");
            const content = readFileSync(fullPath, "utf-8");
            noteEntries.push({
              notebookId: parentDbId,
              title,
              content,
              mtime: st.mtime
            });
          }
        }
      }
      await importDir(rootDir, notebookId);
    });
    if (noteEntries.length > 0) {
      await db.transaction(async (tx) => {
        await tx.insert(notes).values(noteEntries.map((e) => ({
          user_id: uid,
          notebook_id: e.notebookId,
          title: e.title,
          content: e.content,
          is_pinned: 0,
          is_deleted: 0,
          sort_order: 0,
          created_at: e.mtime,
          updated_at: e.mtime
        })));
      });
    }
    return c.json({ code: 200, msg: "import.success", data: null });
  } finally {
    try {
      rmSync(tmpDir, { recursive: true, force: true });
    } catch {}
  }
};

// backend/api/file.ts
import { join as join5 } from "path";
import { existsSync as existsSync3, mkdirSync as mkdirSync3 } from "fs";
var uploadFiles = async (c) => {
  const uid = Number(c.get("uid"));
  const formData = await c.req.formData();
  const fileList = formData.getAll("file[]");
  if (!fileList || fileList.length === 0) {
    return c.json({ code: -1000, msg: "file.upload.no_file", data: null });
  }
  const results = [];
  for (const item of fileList) {
    if (!(item instanceof File))
      continue;
    if (!ALLOWED_IMAGE_TYPES.includes(item.type)) {
      return c.json({ code: -1000, msg: "file.upload.invalid_type", data: null });
    }
    if (item.size > MAX_FILE_SIZE) {
      return c.json({ code: -1000, msg: "file.upload.too_large", data: null });
    }
    const fileId = "zn-" + randomString(8);
    let ext = getExtFromName(item.name);
    if (!ext)
      ext = getExtFromMime(item.type);
    const now = new Date;
    const year = String(now.getFullYear());
    const month = String(now.getMonth() + 1).padStart(2, "0");
    const relativePath = join5("images", String(uid), year, month, `${fileId}.${ext}`);
    const fullPath = join5(FILES_BASE_PATH, relativePath);
    const dir = fullPath.substring(0, fullPath.lastIndexOf("/"));
    if (!existsSync3(dir)) {
      mkdirSync3(dir, { recursive: true });
    }
    await Bun.write(fullPath, item);
    await db.insert(files).values({
      file_id: fileId,
      user_id: uid,
      original_name: item.name,
      file_path: relativePath,
      file_size: item.size,
      mime_type: item.type,
      created_at: now
    }).run();
    results.push({
      file_id: fileId,
      original_name: item.name,
      url: `/files/${relativePath}`
    });
  }
  return c.json({
    code: 200,
    msg: "file.upload.success",
    data: results
  });
};

